const raw=$input.first().json;
const body=(raw.body!==undefined)?raw.body:raw;
const jobId=body.job_id||raw.job_id||("PHY-"+Date.now().toString().slice(-8));
const topic=body.topic||raw.topic;
const sheetRow=body.sheet_row||raw.sheet_row||null;
if(!topic)throw new Error("No topic found. Add a PENDING row in Google Sheet Dashboard (col B=topic, col E=PENDING).");
return[{json:{job_id:jobId,topic:topic,sheet_row:sheetRow,start_time:Date.now()}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content) {
  throw new Error('Gemini script response empty: ' + JSON.stringify(response).slice(0, 300));
}

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

function repairJson(text) {
  let result = '', inString = false, escape = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (escape) { result += ch; escape = false; continue; }
    if (ch === '\\' && inString) { escape = true; result += ch; continue; }
    if (ch === '"') { inString = !inString; result += ch; continue; }
    if (inString) {
      if (ch === '\n') { result += '\\n'; continue; }
      if (ch === '\r') { result += '\\r'; continue; }
      if (ch === '\t') { result += '\\t'; continue; }
    }
    result += ch;
  }
  return result;
}

let parsed;
try { parsed = JSON.parse(rawText); } catch(e1) {
  const start = rawText.indexOf('{'), end = rawText.lastIndexOf('}');
  const block = (start !== -1 && end !== -1) ? rawText.slice(start, end + 1) : rawText;
  try { parsed = JSON.parse(block); } catch(e2) {
    try { parsed = JSON.parse(repairJson(block)); } catch(e3) {
      throw new Error('Failed to parse script JSON: ' + rawText.slice(0, 500));
    }
  }
}

if (!Array.isArray(parsed.scenes) || parsed.scenes.length === 0)
  throw new Error('Script response missing scenes array');

for (const scene of parsed.scenes) {
  if (!scene.class_name)  throw new Error('Scene missing class_name');
  if (!scene.narration)   throw new Error('Scene missing narration: ' + scene.class_name);
  if (!scene.scene_number) scene.scene_number = parsed.scenes.indexOf(scene) + 1;
  if (!scene.visual_hint) scene.visual_hint = '';
}

console.log('Script generated. Scenes: ' + parsed.scenes.map(s => s.class_name + '(' + s.narration.split(' ').length + 'w)').join(', '));

return [{
  json: {
    ...jobConfig,
    scenes: parsed.scenes,
    scene_count: parsed.scenes.length
  }
}];

// Generate ElevenLabs audio per scene, then measure EXACT duration with ffprobe.
// The exact audio duration is passed to Gemini so Manim code can sync perfectly.
const fs    = require('fs');
const https = require('https');
const { execSync } = require('child_process');

const data    = $input.first().json;
const apiKey  = $env.ELEVENLABS_API_KEY;
const voiceId = $env.ELEVENLABS_VOICE_ID;

function httpsPost(hostname, path, headers, body) {
  return new Promise((resolve, reject) => {
    const bodyBuf = Buffer.from(body, 'utf-8');
    const req = https.request(
      { hostname, path, method: 'POST', headers: { ...headers, 'Content-Length': bodyBuf.length } },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => {
          const buf = Buffer.concat(chunks);
          if (res.statusCode !== 200)
            reject(new Error('HTTP ' + res.statusCode + ': ' + buf.toString().slice(0, 300)));
          else
            resolve(buf);
        });
      }
    );
    req.on('error', reject);
    req.write(bodyBuf);
    req.end();
  });
}

const dir = '/data/manim/combined';
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

const scenesWithAudio = [];

for (const scene of data.scenes) {
  const audioPathN8n  = `${dir}/${data.job_id}_scene${scene.scene_number}_audio.mp3`;
  const audioPathCont = `/manim/combined/${data.job_id}_scene${scene.scene_number}_audio.mp3`;

  // Generate audio
  const body = JSON.stringify({
    text:           scene.narration,
    model_id:       'eleven_multilingual_v2',
    voice_settings: { stability: 0.5, similarity_boost: 0.75 }
  });

  let audioBuf;
  try {
    audioBuf = await httpsPost(
      'api.elevenlabs.io',
      `/v1/text-to-speech/${voiceId}`,
      { 'xi-api-key': apiKey, 'Content-Type': 'application/json', 'Accept': 'audio/mpeg' },
      body
    );
  } catch(err) {
    throw new Error('ElevenLabs failed scene ' + scene.scene_number + ': ' + err.message);
  }

  if (audioBuf.length < 100) throw new Error('Empty audio for scene ' + scene.scene_number);
  fs.writeFileSync(audioPathN8n, audioBuf);

  // Measure EXACT audio duration with ffprobe
  let audioDuration = 0;
  try {
    const durOut = execSync(
      `docker exec manim-runner bash -c 'ffprobe -v error -show_entries format=duration -of csv=p=0 "${audioPathCont}"'`,
      { encoding: 'utf-8', timeout: 15000 }
    );
    audioDuration = parseFloat(durOut.trim()) || 0;
  } catch(e) {
    // Fallback: estimate from word count (ElevenLabs ≈ 2.5 words/sec)
    const wordCount = scene.narration.trim().split(/\s+/).length;
    audioDuration = wordCount / 2.5;
    console.warn('ffprobe fallback for scene ' + scene.scene_number + ', estimated=' + audioDuration.toFixed(1) + 's');
  }

  console.log(`Scene ${scene.scene_number} audio: ${audioBuf.length} bytes, duration=${audioDuration.toFixed(2)}s`);

  scenesWithAudio.push({
    ...scene,
    audio_path_n8n:           audioPathN8n,
    audio_path_cont:          audioPathCont,
    audio_duration_seconds:   parseFloat(audioDuration.toFixed(2))
  });
}

const totalAudio = scenesWithAudio.reduce((s, sc) => s + sc.audio_duration_seconds, 0);
console.log('Total audio duration: ' + totalAudio.toFixed(1) + 's');

return [{ json: { ...data, scenes: scenesWithAudio } }];

// Parse Manim code from Gemini and merge with audio data from Generate Scene Audio.
const geminiResponse = $input.first().json;
const audioData      = $('Generate Scene Audio').first().json;

if (!geminiResponse.candidates || !geminiResponse.candidates[0] || !geminiResponse.candidates[0].content) {
  throw new Error('Gemini Manim response empty: ' + JSON.stringify(geminiResponse).slice(0, 300));
}

let rawText = geminiResponse.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// ─── Attempt 1: standard JSON.parse ─────────────────────────────────────────
let parsed = null;
try { parsed = JSON.parse(rawText); } catch(e1) {}

// ─── Attempt 2: repairJson (fixes literal newlines/tabs in strings) ──────────
if (!parsed) {
  function repairJson(text) {
    let out = '', inStr = false, i = 0;
    while (i < text.length) {
      const c = text[i];
      if (!inStr) {
        out += c;
        if (c === '"') inStr = true;
        i++;
      } else if (c === '\\') {
        const n1 = text[i+1] || '';
        const n2 = text[i+2] || '';
        if (n1 === '\\' && n2 === '"') {
          // \\" pattern: treat as escaped quote, keep string open
          out += '\\"'; i += 3;
        } else if (n1 === '\\') {
          out += '\\\\'; i += 2;
        } else if (n1 === '"' || n1 === 'n' || n1 === 't' || n1 === 'r' || n1 === '/') {
          out += c + n1; i += 2;
        } else {
          out += '\\\\'; i++; // escape lone backslash
        }
      } else if (c === '"') {
        out += '"'; inStr = false; i++;
      } else if (c === '\n') {
        out += '\\n'; i++;
      } else if (c === '\r') {
        out += '\\r'; i++;
      } else if (c === '\t') {
        out += '\\t'; i++;
      } else {
        out += c; i++;
      }
    }
    return out;
  }
  const start = rawText.indexOf('{'), end = rawText.lastIndexOf('}');
  const block = (start !== -1 && end !== -1) ? rawText.slice(start, end + 1) : rawText;
  try { parsed = JSON.parse(repairJson(block)); } catch(e2) {}
}

// ─── Attempt 3: direct character-by-character code block extractor ───────────
// Handles any remaining escaping issues by walking the raw text directly.
if (!parsed) {
  console.warn('JSON.parse and repairJson both failed — using direct extractor');
  function extractBlocks(text) {
    const blocks = [];
    let pos = 0;
    while (pos < text.length) {
      // Find next \"code\" key
      const keyIdx = text.indexOf('"code"', pos);
      if (keyIdx === -1) break;
      // Skip to colon then to opening quote
      let ci = keyIdx + 6;
      while (ci < text.length && text[ci] !== ':') ci++;
      ci++; // skip ':'
      while (ci < text.length && (text[ci] === ' ' || text[ci] === '\n' || text[ci] === '\r' || text[ci] === '\t')) ci++;
      if (text[ci] !== '"') { pos = keyIdx + 6; continue; }
      ci++; // skip opening quote

      // Read string value
      let code = '';
      let i = ci;
      while (i < text.length) {
        const c = text[i];
        if (c === '\\') {
          const n1 = text[i+1] || '';
          const n2 = text[i+2] || '';
          if (n1 === 'n')  { code += '\n'; i += 2; }
          else if (n1 === 't')  { code += '\t'; i += 2; }
          else if (n1 === 'r')  { code += '\r'; i += 2; }
          else if (n1 === '"') { code += '"';  i += 2; }
          else if (n1 === '\\' && n2 === '"') { code += '"'; i += 3; } // \\" → "
          else if (n1 === '\\') { code += '\\'; i += 2; }
          else { code += n1; i += 2; }
        } else if (c === '"') {
          i++; break; // end of string
        } else if (c === '\n') {
          code += '\n'; i++; // literal newline inside string
        } else {
          code += c; i++;
        }
      }
      if (code.trim().length > 20) blocks.push({ code, endPos: i });
      pos = i;
    }
    return blocks;
  }

  // Also extract class_names and scene_numbers by order
  const blocks = extractBlocks(rawText);
  if (blocks.length === 0) throw new Error('Could not extract any code blocks from Gemini response. Raw: ' + rawText.slice(0, 500));

  const classMatches = [...rawText.matchAll(/"class_name"\s*:\s*"([^"]+)"/g)].map(m => m[1]);
  const numMatches   = [...rawText.matchAll(/"scene_number"\s*:\s*(\d+)/g)].map(m => parseInt(m[1]));

  parsed = {
    scenes: blocks.map((b, idx) => ({
      scene_number: numMatches[idx] || (idx + 1),
      class_name:   classMatches[idx] || ('Scene' + (idx + 1)),
      code:         b.code
    }))
  };
  console.log('Extracted ' + parsed.scenes.length + ' code blocks via direct extractor');
}

if (!Array.isArray(parsed.scenes) || parsed.scenes.length === 0)
  throw new Error('Manim response missing scenes array');

// Merge Manim code into the existing scenes (which have audio paths + durations)
const mergedScenes = audioData.scenes.map(existingScene => {
  const manim = parsed.scenes.find(
    m => m.class_name === existingScene.class_name || m.scene_number === existingScene.scene_number
  );
  if (!manim || !manim.code) throw new Error('No Manim code for scene: ' + existingScene.class_name);
  return { ...existingScene, code: manim.code };
});

console.log('Manim code merged for: ' + mergedScenes.map(s => s.class_name).join(', '));

return [{ json: { ...audioData, scenes: mergedScenes } }];

const data=$input.first().json;
const cfg=$("Set Job Config").first().json;
return[{json:{job_id:data.job_id,scenes:data.scenes,scene_count:data.scenes.length,start_time:data.start_time,sheet_row:cfg.sheet_row||null}}];

const res=$input.first().json;
const rows=res.values||[];
let found=null;
for(let i=0;i<rows.length;i++){
  const s=(rows[i][4]||"" ).toString().toUpperCase().trim();
  if(s==="PENDING"){found={idx:i,row:rows[i]};break;}
}
if(!found)throw new Error("No PENDING topic found in Dashboard tab.
Open your Google Sheet -> Dashboard -> set STATUS (col E) = PENDING for a row.");
const sheetRow=found.idx+4;
const topic=(found.row[1]||"").trim();
if(!topic)throw new Error("PENDING row found but Topic (col B) is empty.");
const jobId=(found.row[0]||"").trim()||"PHY-"+Date.now().toString().slice(-8);
console.log("Sheet row "+sheetRow+" | "+jobId+" | "+topic);
return[{json:{job_id:jobId,topic:topic,sheet_row:sheetRow,source:"google_sheet"}}];
